// ===== TopWorstSellers.js =====
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './TopWorstSellers.css';
import Optionbar from './Optionbar';
import { segmentOptions, highlightOptions, seasonOptions, locationOptions } from './Icons/optionbarOptions';

// Import category icons
import beerIcon from './Icons/beer.svg';
import cocktailIcon from './Icons/cocktail.svg';
import coffeeIcon from './Icons/coffee.svg';
import juicesIcon from './Icons/juices.svg';
import mocktailsIcon from './Icons/mocktails.svg';
import softdrinksIcon from './Icons/softdrinks.svg';
import spiritsIcon from './Icons/spirits.svg';
import sportdrinksIcon from './Icons/sportdrinks.svg';
import teaIcon from './Icons/tea.svg';
import wineIcon from './Icons/wine.svg';

// Import highlight icons
import highMarginIcon from './Icons/highmargin.svg';
import trendingIcon from './Icons/trending.svg';
import ecoIcon from './Icons/ecofriendly.svg';
import summerIcon from './Icons/summer.svg';
import winterIcon from './Icons/winter.svg';
import autumnIcon from './Icons/autumn.svg';
import springIcon from './Icons/spring.svg';

// Import production location icons
import locallyIcon from './Icons/locallyproduced.svg';
import belgiumIcon from './Icons/madeinbelgium.svg';
import globalIcon from './Icons/globallysourced.svg';

// Map category names to icons
const categoryIconMap = {
    Beer: beerIcon,
    Cocktail: cocktailIcon,
    Coffee: coffeeIcon,
    Juices: juicesIcon,
    Mocktails: mocktailsIcon,
    'Soft Drinks': softdrinksIcon,
    Spirits: spiritsIcon,
    'Sport/Energy Drinks': sportdrinksIcon,
    'Tea & Infusions': teaIcon,
    Wine: wineIcon
};

// Map season to icons
const seasonIconMap = {
    Summer: summerIcon,
    Winter: winterIcon,
    Autumn: autumnIcon,
    Spring: springIcon
};

export default function TopWorstSellers() {
    const [searchTerm, setSearchTerm] = useState('');
    const [sortOrder, setSortOrder]   = useState('top');
    const [items, setItems]           = useState([]);
    const [businessCity, setBusinessCity] = useState('');
    const [loading, setLoading]       = useState(true);
    const [error, setError]           = useState(null);

    // Filters state controlled by Optionbar
    const [filters, setFilters] = useState({
        segments:   new Set(segmentOptions.map(o => o.id)),
        highlights: new Set(highlightOptions.map(o => o.id)),
        seasons:    new Set(seasonOptions.map(o => o.id)),
        locations:  new Set(locationOptions.map(o => o.id)),
    });

    // fetch business city
    useEffect(() => {
        axios.get('/api/business-info', { withCredentials:true })
            .then(res => setBusinessCity(res.data.city || ''))
            .catch(console.error);
    }, []);

    // fetch sales
    useEffect(() => {
        setLoading(true);
        axios.get('/api/sales', { withCredentials:true })
            .then(res => {
                const mapped = res.data.map(i => ({
                    id:           i.id_menu_item,
                    name:         i.item_name,
                    count:        i.total_sold ?? i.sold_count,
                    categoryId:   i.id_category,
                    category:     i.category,
                    high_margin:  i.is_high_margin === 1,
                    trending:     i.is_trending === 1,
                    eco_friendly: i.eco_friendly === 'Yes' || i.eco_friendly === 1,
                    season:       i.season || 'Unknown',
                    prodCity:     i.stad,
                    prodCountry:  i.land
                }));
                setItems(mapped);
            })
            .catch(err => { console.error(err); setError('Kon verkoopcijfers niet laden'); })
            .finally(() => setLoading(false));
    }, []);

    if(loading) return <p>Loading…</p>;
    if(error)   return <p className="error">{error}</p>;

    // sort
    const sorted = [...items].sort((a,b) => sortOrder==='top' ? b.count - a.count : a.count - b.count);

    // filtered by search + filters
    const visible = sorted.filter(item => {
        // search
        if(!item.name.toLowerCase().includes(searchTerm.toLowerCase())) return false;
        // segment
        if(!filters.segments.has(item.categoryId)) return false;
        // highlights: must match at least one selected highlight
        const highlightChecks = [
            {id: highlightOptions.find(o=>o.label==='High Margin').id,       ok: item.high_margin},
            {id: highlightOptions.find(o=>o.label==='Trending').id,          ok: item.trending},
            {id: highlightOptions.find(o=>o.label==='Eco Friendly').id,      ok: item.eco_friendly}
        ];
        if(highlightChecks.some(h=>filters.highlights.has(h.id))){
            if(!highlightChecks.some(h=>filters.highlights.has(h.id) && h.ok)) return false;
        }
        // seasons
        const seasonOpt = seasonOptions.find(o=>o.label===item.season);
        if(seasonOpt && !filters.seasons.has(seasonOpt.id)) return false;
        // locations
        const locOpt = item.prodCity===businessCity
            ? locationOptions.find(o=>o.label==='Locally Produced')
            : (item.prodCountry==='Belgium'
                ? locationOptions.find(o=>o.label==='Made in Belgium')
                : locationOptions.find(o=>o.label==='Sourced Globally'));
        if(locOpt && !filters.locations.has(locOpt.id)) return false;

        return true;
    });

    return (
        <div className="top-worst-container">
            <div className="centre-content">
                <div className="list-header">
                    <div className="header-title">
                        <p>Top & Worst</p>
                        <h2 className="section-title">Menu‑items</h2>
                    </div>
                    <div className="section-order">
                        <span className={`order-button ${sortOrder==='top'?'active':''}`} onClick={()=>setSortOrder('top')}>Top ↑</span>
                        <span className={`order-button ${sortOrder==='worst'?'active':''}`} onClick={()=>setSortOrder('worst')}>Worst ↓</span>
                    </div>
                    <div className="search-bar">
                        <input value={searchTerm} onChange={e=>setSearchTerm(e.target.value)} placeholder="Search…" />
                    </div>
                </div>
                <ul className="items-list">
                    {visible.map((item,idx)=>(
                        <li key={item.id} className="item">
                            <div className="item-main">
                                <span className="item-rank">{idx+1}.</span>
                                <span className="item-name">{item.name}</span>
                                <div className="item-icons">
                                    {item.category && categoryIconMap[item.category] && <img src={categoryIconMap[item.category]} alt={item.category} className="category-icon" />}
                                    {item.high_margin  && <img src={highMarginIcon} alt="High Margin" className="highlight-icon" />}
                                    {item.trending     && <img src={trendingIcon}    alt="Trending"      className="highlight-icon" />}
                                    {item.eco_friendly && <img src={ecoIcon}         alt="Eco"           className="highlight-icon" />}
                                    {item.season!=='Unknown' && seasonIconMap[item.season] && <img src={seasonIconMap[item.season]} alt={item.season} className="highlight-icon" />}
                                    {item.prodCity && item.prodCountry &&
                                        <img src={ item.prodCity===businessCity ? locallyIcon : (item.prodCountry==='Belgium'? belgiumIcon: globalIcon) }
                                             alt="Location" className="location-icon" />}
                                </div>
                            </div>
                            <span className="item-count">{item.count} sold</span>
                        </li>
                    ))}
                </ul>
            </div>
            <Optionbar filters={filters} onChange={setFilters} />
        </div>
    );
}
